// src/pages/Paiements.jsx
import React, { useState, useEffect } from 'react';
import { getPaiements, addPaiement } from '../services/api';

function Paiements() {
  const [paiements, setPaiements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const [formData, setFormData] = useState({
    montant: '',
    date_paiement: new Date().toISOString().split('T')[0],
    mode_paiement: 'Espèces',
    statut: 'Payé',
    id_abonnement: '',
  });

  const fetchPaiements = async () => {
    try {
      const res = await getPaiements();
      setPaiements(res.data || []);
      setLoading(false);
    } catch (err) {
      setError('Erreur lors du chargement des paiements');
      setLoading(false);
      console.error(err);
    }
  };

  useEffect(() => {
    fetchPaiements();
  }, []);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await addPaiement(formData);
      alert('Paiement enregistré avec succès !');
      setFormData({
        montant: '',
        date_paiement: new Date().toISOString().split('T')[0],
        mode_paiement: 'Espèces',
        statut: 'Payé',
        id_abonnement: '',
      });
      fetchPaiements(); // Recharger la liste
    } catch (err) {
      alert('Erreur lors de l’enregistrement du paiement');
      console.error(err);
    }
  };

  if (loading) return <div className="text-center mt-5">Chargement des paiements...</div>;

  if (error) return <div className="alert alert-danger text-center mt-5">{error}</div>;

  return (
    <div className="container mt-5">
      <h2 className="mb-4 text-center">Gestion des Paiements</h2>

      {/* Formulaire d'enregistrement */}
      <div className="card shadow mb-5">
        <div className="card-header bg-success text-white">
          <h5 className="mb-0">Enregistrer un nouveau paiement</h5>
        </div>
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="row g-3">
              <div className="col-md-4">
                <label className="form-label">Montant (DH)</label>
                <input
                  type="number"
                  name="montant"
                  step="0.01"
                  min="0"
                  className="form-control"
                  value={formData.montant}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="col-md-4">
                <label className="form-label">Date du paiement</label>
                <input
                  type="date"
                  name="date_paiement"
                  className="form-control"
                  value={formData.date_paiement}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="col-md-4">
                <label className="form-label">Mode de paiement</label>
                <select
                  name="mode_paiement"
                  className="form-select"
                  value={formData.mode_paiement}
                  onChange={handleChange}
                  required
                >
                  <option value="Espèces">Espèces</option>
                  <option value="Carte bancaire">Carte bancaire</option>
                  <option value="Virement">Virement</option>
                  <option value="Mobile Money">Mobile Money</option>
                </select>
              </div>

              <div className="col-md-6">
                <label className="form-label">Statut</label>
                <select
                  name="statut"
                  className="form-select"
                  value={formData.statut}
                  onChange={handleChange}
                  required
                >
                  <option value="Payé">Payé</option>
                  <option value="En attente">En attente</option>
                  <option value="Annulé">Annulé</option>
                </select>
              </div>

              <div className="col-md-6">
                <label className="form-label">ID Abonnement</label>
                <input
                  type="number"
                  name="id_abonnement"
                  className="form-control"
                  placeholder="ID de l'abonnement concerné"
                  value={formData.id_abonnement}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="mt-4 text-end">
              <button type="submit" className="btn btn-success">
                Enregistrer le paiement
              </button>
            </div>
          </form>
        </div>
      </div>

      {/* Liste des paiements */}
      <h4 className="mb-3">Historique des paiements</h4>

      {paiements.length === 0 ? (
        <div className="alert alert-info text-center">
          Aucun paiement enregistré pour le moment
        </div>
      ) : (
        <div className="table-responsive">
          <table className="table table-striped table-hover table-bordered">
            <thead className="table-dark">
              <tr>
                <th>ID</th>
                <th>Montant (DH)</th>
                <th>Date</th>
                <th>Mode</th>
                <th>Statut</th>
                <th>Abonnement</th>
                <th>Membre</th>
              </tr>
            </thead>
            <tbody>
              {paiements.map((p) => (
                <tr key={p.id_paiement}>
                  <td>{p.id_paiement}</td>
                  <td>{p.montant} DH</td>
                  <td>{p.date_paiement}</td>
                  <td>{p.mode_paiement}</td>
                  <td className={
                    p.statut === 'Payé' ? 'text-success fw-bold' :
                    p.statut === 'En attente' ? 'text-warning fw-bold' :
                    'text-danger fw-bold'
                  }>
                    {p.statut}
                  </td>
                  <td>{p.type_abonnement}</td>
                  <td>{p.nom_membre}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Paiements;
